def is_multiply_prime(a):
    if a < 2:
        return False

    # Get prime factorization
    factors = []
    n = a
    d = 2
    while d * d <= n:
        while n % d == 0:
            factors.append(d)
            n //= d
        d += 1
    if n > 1:
        factors.append(n)

    # Check if exactly 3 prime factors (with multiplicity)
    return len(factors) == 3

def words_in_sentence(sentence):
    def is_prime(n):
        if n < 2:
            return False
        if n == 2:
            return True
        if n % 2 == 0:
            return False
        # Check odd divisors up to sqrt(n)
        i = 3
        while i * i <= n:
            if n % i == 0:
                return False
            i += 2
        return True

    words = sentence.split()
    prime_length_words = []

    for word in words:
        if is_prime(len(word)):
            prime_length_words.append(word)

    return " ".join(prime_length_words)

