def move_one_ball(arr):
    # Handle edge cases
    if len(arr) <= 1:
        return True

    # Count break points where arr[i] > arr[i+1]
    break_points = 0
    for i in range(len(arr) - 1):
        if arr[i] > arr[i + 1]:
            break_points += 1

    # If no break points, already sorted
    if break_points == 0:
        return True

    # If more than one break point, impossible
    if break_points > 1:
        return False

    # Exactly one break point: check if rotation is valid
    # The last element must be <= first element for proper rotation
    return arr[-1] <= arr[0]

def even_odd_palindrome(n):
    even_count = 0
    odd_count = 0

    for i in range(1, n + 1):
        # Check if i is a palindrome
        s = str(i)
        if s == s[::-1]:
            if i % 2 == 0:
                even_count += 1
            else:
                odd_count += 1

    return (even_count, odd_count)

