    if len(arr) <= 1:
        return True

    sorted_arr = sorted(arr)
    n = len(arr)

    # Check all possible rotations
    for i in range(n):
        # rotation starting at index i: arr[i:] + arr[:i]
        rotated = arr[i:] + arr[:i]
        if rotated == sorted_arr:
            return True

    return False

