def select_words(s, n):
    if not s:
        return []

    # Define vowels (case insensitive)
    vowels = set('aeiouAEIOU')

    words = s.split()
    result = []

    for word in words:
        # Count consonants in this word
        consonant_count = 0
        for char in word:
            if char.isalpha() and char not in vowels:
                consonant_count += 1

        if consonant_count == n:
            result.append(word)

    return result

