def prod_signs(arr):
    if len(arr) == 0:
        return None

    # Calculate sum of magnitudes (absolute values)
    sum_magnitudes = sum(abs(x) for x in arr)

    # Calculate product of signs
    # sign is 1 for positive, -1 for negative, 0 for zero
    product_signs = 1
    for x in arr:
        if x > 0:
            sign = 1
        elif x < 0:
            sign = -1
        else:  # x == 0
            sign = 0
        product_signs *= sign
        # Early exit optimization: if product becomes 0, it stays 0
        if product_signs == 0:
            break

    return sum_magnitudes * product_signs

from typing import List

def factorize(n: int) -> List[int]:
    if n <= 1:
        return []

    factors = []
    # Handle factor 2 separately to make the loop more efficient
    while n % 2 == 0:
        factors.append(2)
        n //= 2

    # Check odd factors from 3 onwards
    factor = 3
    while factor * factor <= n:
        while n % factor == 0:
            factors.append(factor)
            n //= factor
        factor += 2

    # If n is still greater than 1, then it's a prime factor
    if n > 1:
        factors.append(n)

    return factors

