def change_base(x: int, base: int) -> str:
    if x == 0:
        return '0'

    result = ''
    num = abs(x)

    while num > 0:
        remainder = num % base
        result = str(remainder) + result
        num = num // base

    # Handle negative numbers
    if x < 0:
        result = '-' + result

    return result

def is_prime(n):
    """
    Return True if a given number is prime, and False otherwise.

    A prime number is a natural number greater than 1 that has no positive
    divisors other than 1 and itself.
    """
    # Handle edge cases
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False

    # Check odd divisors up to sqrt(n)
    i = 3
    while i * i <= n:
        if n % i == 0:
            return False
        i += 2

    return True

def is_prime(n):
    """
    Return True if a given number is prime, and False otherwise.

    A prime number is a natural number greater than 1 that has no positive
    divisors other than 1 and itself.
    """
    # Handle edge cases
    if n <= 1:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False

    # Check odd divisors up to sqrt(n)
    i = 3
    while i * i <= n:
        if n % i == 0:
            return False
        i += 2

    return True

