def decode_cyclic(s: str) -> str:
    """
    Decodes a string that was encoded with a cyclic shift (Caesar cipher).
    Assumes the encoding used a shift of 3 positions forward, so we shift back by 3.
    """
    result = []
    for char in s:
        if 'a' <= char <= 'z':
            # Shift lowercase letters back by 3 positions cyclically
            shifted = chr((ord(char) - ord('a') - 3) % 26 + ord('a'))
            result.append(shifted)
        elif 'A' <= char <= 'Z':
            # Shift uppercase letters back by 3 positions cyclically
            shifted = chr((ord(char) - ord('A') - 3) % 26 + ord('A'))
            result.append(shifted)
        else:
            # Non-alphabetic characters remain unchanged
            result.append(char)

    return ''.join(result)

