def order_by_points(nums):
    def digit_sum(n):
        # Calculate sum of digits of absolute value
        s = str(abs(n))
        return sum(int(digit) for digit in s)

    # Sort by digit sum; Python's sorted is stable, so same digit sum elements keep relative order
    return sorted(nums, key=digit_sum)

